const text = $json.textInput;

if (!text || text.trim().length === 0) {
  throw new Error('No text received! Type something in the chat before running this workflow.');
}

// Turn the plain text into a real .txt file (base64 encoded, required by n8n's binary format)
return {
  json: { text },
  binary: {
    data: {
      data: Buffer.from(text, 'utf8').toString('base64'),
      mimeType: 'text/plain',
      fileName: 'narration.txt'
    }
  }
};
